# Terraform: 确保 ASG 跨越多个 AZ
resource "aws_autoscaling_group" "<example_resource_name>" {
  min_size = 1
  max_size = 1

  launch_template {
    id      = "<example_resource_id>"
    version = "$Latest"
  }

  vpc_zone_identifier = [
    "<subnet_id_az1>",
    "<subnet_id_az2>" # 关键：不同 AZ 中的两个子网以通过检查
  ]
}
```
